INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r1_bone_health', 'Adequate calcium intake is the foundational requirement for bone mineral density. Calcium is the primary mineral constituent of hydroxyapatite, the crystalline structure of bone. Supplementation is particularly important when dietary calcium is insufficient, and is a standard recommendation for fracture and osteoporosis prevention in clinical guidelines worldwide.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r1_fracture_prevention', 'Adequate calcium intake is the foundational requirement for bone mineral density. Calcium is the primary mineral constituent of hydroxyapatite, the crystalline structure of bone. Supplementation is particularly important when dietary calcium is insufficient, and is a standard recommendation for fracture and osteoporosis prevention in clinical guidelines worldwide.', 'goal', '52e417c0-bfa8-433b-9567-9b4bafd6cfe8', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r1_osteoporosis_prevention', 'Adequate calcium intake is the foundational requirement for bone mineral density. Calcium is the primary mineral constituent of hydroxyapatite, the crystalline structure of bone. Supplementation is particularly important when dietary calcium is insufficient, and is a standard recommendation for fracture and osteoporosis prevention in clinical guidelines worldwide.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r1_bone_health', 'Vitamin D is essential for intestinal calcium absorption and bone mineralization. Without adequate vitamin D, the body cannot effectively absorb calcium, undermining the entire bone health framework. Clinical trials demonstrate that combined calcium and vitamin D supplementation reduces fracture risk, particularly in older adults and those with low sun exposure.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r1_fracture_prevention', 'Vitamin D is essential for intestinal calcium absorption and bone mineralization. Without adequate vitamin D, the body cannot effectively absorb calcium, undermining the entire bone health framework. Clinical trials demonstrate that combined calcium and vitamin D supplementation reduces fracture risk, particularly in older adults and those with low sun exposure.', 'goal', '52e417c0-bfa8-433b-9567-9b4bafd6cfe8', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r1_osteoporosis_prevention', 'Vitamin D is essential for intestinal calcium absorption and bone mineralization. Without adequate vitamin D, the body cannot effectively absorb calcium, undermining the entire bone health framework. Clinical trials demonstrate that combined calcium and vitamin D supplementation reduces fracture risk, particularly in older adults and those with low sun exposure.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r1_bone_health', 'Vitamin K is required for the carboxylation of osteocalcin, a bone matrix protein that binds calcium and is critical for proper bone mineralization. Undercarboxylated osteocalcin is associated with lower bone mineral density and higher fracture risk. Observational data show that higher vitamin K intake correlates with greater BMD and lower hip fracture incidence.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r1_fracture_prevention', 'Vitamin K is required for the carboxylation of osteocalcin, a bone matrix protein that binds calcium and is critical for proper bone mineralization. Undercarboxylated osteocalcin is associated with lower bone mineral density and higher fracture risk. Observational data show that higher vitamin K intake correlates with greater BMD and lower hip fracture incidence.', 'goal', '52e417c0-bfa8-433b-9567-9b4bafd6cfe8', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r1_osteoporosis_prevention', 'Vitamin K is required for the carboxylation of osteocalcin, a bone matrix protein that binds calcium and is critical for proper bone mineralization. Undercarboxylated osteocalcin is associated with lower bone mineral density and higher fracture risk. Observational data show that higher vitamin K intake correlates with greater BMD and lower hip fracture incidence.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r1_bone_health', 'Approximately 60% of total body magnesium is stored in bone. Magnesium influences both osteoblast and osteoclast activity and is required for vitamin D activation (conversion to its active form 1,25-dihydroxyvitamin D). Low magnesium intake is associated with lower bone mineral density and increased osteoporosis risk in population studies.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r1_osteoporosis_prevention', 'Approximately 60% of total body magnesium is stored in bone. Magnesium influences both osteoblast and osteoclast activity and is required for vitamin D activation (conversion to its active form 1,25-dihydroxyvitamin D). Low magnesium intake is associated with lower bone mineral density and increased osteoporosis risk in population studies.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('phosphorus_r1_bone_health', 'Phosphorus, together with calcium, forms hydroxyapatite — the principal mineral compound of bone. Adequate phosphorus is necessary for bone matrix formation and maintenance. Most populations meet requirements through diet; supplementation is relevant primarily in cases of inadequate intake or malabsorption.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r1_bone_health', 'Vitamin C is required as a cofactor for prolyl and lysyl hydroxylases, the enzymes responsible for collagen crosslinking and maturation. Collagen constitutes the organic scaffold of bone upon which mineral is deposited. Adequate vitamin C status therefore supports the structural integrity of bone matrix independently of calcium and vitamin D.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r1_fracture_prevention', 'Vitamin C is required as a cofactor for prolyl and lysyl hydroxylases, the enzymes responsible for collagen crosslinking and maturation. Collagen constitutes the organic scaffold of bone upon which mineral is deposited. Adequate vitamin C status therefore supports the structural integrity of bone matrix independently of calcium and vitamin D.', 'goal', '52e417c0-bfa8-433b-9567-9b4bafd6cfe8', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r1_bone_health', 'Zinc is a cofactor for alkaline phosphatase, an enzyme expressed by osteoblasts and required for bone mineralization. Zinc deficiency is associated with impaired bone formation and reduced bone mass. Adequate zinc supports osteoblast function and bone collagen synthesis.', 'goal', 'bddb4e24-76a9-402a-96ce-6dee4a360a94', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r1_osteoporosis_prevention', 'Zinc is a cofactor for alkaline phosphatase, an enzyme expressed by osteoblasts and required for bone mineralization. Zinc deficiency is associated with impaired bone formation and reduced bone mass. Adequate zinc supports osteoblast function and bone collagen synthesis.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r2_joint_health', 'Vitamin D modulates immune function and has anti-inflammatory properties relevant to autoimmune arthropathies. Low vitamin D levels are consistently associated with higher disease activity in rheumatoid arthritis and with progression of osteoarthritis. Ensuring adequate vitamin D status is a reasonable adjunct in joint health goals.', 'goal', 'c5652493-733b-4391-b438-6e59da3ce5ce', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r2_arthritis_support', 'Vitamin D modulates immune function and has anti-inflammatory properties relevant to autoimmune arthropathies. Low vitamin D levels are consistently associated with higher disease activity in rheumatoid arthritis and with progression of osteoarthritis. Ensuring adequate vitamin D status is a reasonable adjunct in joint health goals.', 'goal', 'b3f1a5c6-a26e-487f-afdd-55fa2c7da28f', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r2_joint_health', 'Articular cartilage is predominantly type II collagen, which requires vitamin C for hydroxylation and crosslinking. Adequate vitamin C supports cartilage integrity and may slow structural joint degradation. Observational data suggest that low vitamin C intake is associated with increased cartilage loss and arthritis progression.', 'goal', 'c5652493-733b-4391-b438-6e59da3ce5ce', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r2_arthritis_support', 'Articular cartilage is predominantly type II collagen, which requires vitamin C for hydroxylation and crosslinking. Adequate vitamin C supports cartilage integrity and may slow structural joint degradation. Observational data suggest that low vitamin C intake is associated with increased cartilage loss and arthritis progression.', 'goal', 'b3f1a5c6-a26e-487f-afdd-55fa2c7da28f', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r1_joint_health', 'Selenium is a component of glutathione peroxidase, a key antioxidant enzyme in synovial tissue. Oxidative stress plays a central role in the pathogenesis of both osteoarthritis and rheumatoid arthritis. Low selenium status has been associated with greater arthritis severity in population studies.', 'goal', 'c5652493-733b-4391-b438-6e59da3ce5ce', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r1_arthritis_support', 'Selenium is a component of glutathione peroxidase, a key antioxidant enzyme in synovial tissue. Oxidative stress plays a central role in the pathogenesis of both osteoarthritis and rheumatoid arthritis. Low selenium status has been associated with greater arthritis severity in population studies.', 'goal', 'b3f1a5c6-a26e-487f-afdd-55fa2c7da28f', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r3_muscle_health', 'Vitamin D receptors are present in skeletal muscle cells. Vitamin D deficiency is associated with proximal muscle weakness, impaired muscle function, and increased fall risk. Clinical trials demonstrate that vitamin D supplementation improves muscle strength and physical performance, particularly in individuals who are deficient, and is clinically relevant for sarcopenia prevention.', 'goal', 'dcf36066-0174-47f9-abb1-97c7e239f955', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r2_muscle_health', 'Magnesium is essential for ATP production (the primary energy currency of muscle contraction) and for calcium-mediated regulation of actin-myosin interaction. Magnesium deficiency manifests as muscle cramps, weakness, and tremors. Adequate magnesium is foundational for normal neuromuscular function and muscle recovery.', 'goal', 'dcf36066-0174-47f9-abb1-97c7e239f955', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r1_muscle_health', 'Vitamin E is a fat-soluble antioxidant concentrated in cell membranes, including those of skeletal muscle fibers. It protects muscle membrane polyunsaturated fatty acids from oxidative damage during exercise-induced free radical generation. Vitamin E deficiency causes a myopathy in animals and in humans with fat malabsorption disorders.', 'goal', 'dcf36066-0174-47f9-abb1-97c7e239f955', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('potassium_r1_muscle_health', 'Potassium is the primary intracellular cation and is critical for maintaining the resting membrane potential of muscle cells. Inadequate potassium impairs muscle contraction, causes fatigue, weakness, and cramping. Adequate potassium is essential for normal skeletal and smooth muscle function.', 'goal', 'dcf36066-0174-47f9-abb1-97c7e239f955', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r1_cardiovascular_health', 'Folate (vitamin B9) is required for the remethylation of homocysteine to methionine. Elevated homocysteine is an independent cardiovascular risk factor associated with endothelial dysfunction, arterial stiffness, thrombosis, and increased risk of stroke and coronary artery disease. Folic acid supplementation reliably lowers homocysteine levels and has demonstrated cardiovascular benefit in meta-analyses.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r1_circulation_support', 'Folate (vitamin B9) is required for the remethylation of homocysteine to methionine. Elevated homocysteine is an independent cardiovascular risk factor associated with endothelial dysfunction, arterial stiffness, thrombosis, and increased risk of stroke and coronary artery disease. Folic acid supplementation reliably lowers homocysteine levels and has demonstrated cardiovascular benefit in meta-analyses.', 'goal', '919247a7-6605-4a9c-9196-c1e20ea66f08', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r1_cardiovascular_health', 'Vitamin B6 (as pyridoxal-5''-phosphate) is required for the transsulfuration pathway that converts homocysteine to cystathionine, the main route for homocysteine elimination. B6 deficiency results in elevated homocysteine, contributing to cardiovascular risk. B6 is typically combined with folate and B12 in homocysteine-lowering protocols.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r1_circulation_support', 'Vitamin B6 (as pyridoxal-5''-phosphate) is required for the transsulfuration pathway that converts homocysteine to cystathionine, the main route for homocysteine elimination. B6 deficiency results in elevated homocysteine, contributing to cardiovascular risk. B6 is typically combined with folate and B12 in homocysteine-lowering protocols.', 'goal', '919247a7-6605-4a9c-9196-c1e20ea66f08', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b12_r1_cardiovascular_health', 'Vitamin B12 is required, alongside folate, for the methylation cycle that converts homocysteine back to methionine. Deficiency in B12 elevates homocysteine and is associated with increased cardiovascular risk. The combination of B12 + folate + B6 is the standard nutritional protocol for homocysteine lowering.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b12_r1_circulation_support', 'Vitamin B12 is required, alongside folate, for the methylation cycle that converts homocysteine back to methionine. Deficiency in B12 elevates homocysteine and is associated with increased cardiovascular risk. The combination of B12 + folate + B6 is the standard nutritional protocol for homocysteine lowering.', 'goal', '919247a7-6605-4a9c-9196-c1e20ea66f08', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b3_r1_cholesterol_management', 'Nicotinic acid (niacin) at pharmacological doses is the most effective agent for raising HDL cholesterol and also reduces LDL and triglycerides. It is used clinically in dyslipidemia management. The lipid-modifying effects are specific to the nicotinic acid form; nicotinamide does not share this property.', 'goal', '7e84e7b4-fa90-46bd-ac4c-216aac4b5c90', 10, 'accumulate', true, '{"warning":"HIGH-DOSE NICOTINIC ACID (>500 MG/DAY) CAN CAUSE FLUSHING, HEPATOTOXICITY, AND HYPERGLYCEMIA. PHARMACOLOGICAL NIACIN DOSES SHOULD ONLY BE USED UNDER MEDICAL SUPERVISION.","remark":"The lipid-modifying effects require doses far above the RDA (14–16 mg/day) and are pharmacological rather than nutritional."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b3_r1_cardiovascular_health', 'Nicotinic acid (niacin) at pharmacological doses is the most effective agent for raising HDL cholesterol and also reduces LDL and triglycerides. It is used clinically in dyslipidemia management. The lipid-modifying effects are specific to the nicotinic acid form; nicotinamide does not share this property.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, '{"warning":"HIGH-DOSE NICOTINIC ACID (>500 MG/DAY) CAN CAUSE FLUSHING, HEPATOTOXICITY, AND HYPERGLYCEMIA. PHARMACOLOGICAL NIACIN DOSES SHOULD ONLY BE USED UNDER MEDICAL SUPERVISION.","remark":"The lipid-modifying effects require doses far above the RDA (14–16 mg/day) and are pharmacological rather than nutritional."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b3_r2_cholesterol_management', 'Doses of nicotinic acid above 2,000 mg/day carry significant risk of hepatotoxicity, gastrointestinal distress, hyperglycemia, and gout. These doses are in the pharmacological range and should not be used without medical monitoring, especially given the availability of safer lipid-lowering medications.', 'goal', '7e84e7b4-fa90-46bd-ac4c-216aac4b5c90', 5, 'accumulate', true, '{"warning":"HIGH-DOSE NICOTINIC ACID ABOVE 2000 MG/DAY IS ASSOCIATED WITH SERIOUS HEPATOTOXICITY AND SHOULD NOT BE TAKEN WITHOUT MEDICAL SUPERVISION."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b3_r2_cardiovascular_health', 'Doses of nicotinic acid above 2,000 mg/day carry significant risk of hepatotoxicity, gastrointestinal distress, hyperglycemia, and gout. These doses are in the pharmacological range and should not be used without medical monitoring, especially given the availability of safer lipid-lowering medications.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 5, 'accumulate', true, '{"warning":"HIGH-DOSE NICOTINIC ACID ABOVE 2000 MG/DAY IS ASSOCIATED WITH SERIOUS HEPATOTOXICITY AND SHOULD NOT BE TAKEN WITHOUT MEDICAL SUPERVISION."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r3_blood_pressure_support', 'Magnesium acts as a natural calcium channel blocker and promotes vascular smooth muscle relaxation, thereby lowering peripheral resistance and blood pressure. Meta-analyses of RCTs show that magnesium supplementation produces modest but statistically significant reductions in both systolic and diastolic blood pressure, particularly in hypertensive individuals and those with low magnesium status.', 'goal', '69d1c252-751c-49f5-8669-616f10db6658', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r3_cardiovascular_health', 'Magnesium acts as a natural calcium channel blocker and promotes vascular smooth muscle relaxation, thereby lowering peripheral resistance and blood pressure. Meta-analyses of RCTs show that magnesium supplementation produces modest but statistically significant reductions in both systolic and diastolic blood pressure, particularly in hypertensive individuals and those with low magnesium status.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('potassium_r2_blood_pressure_support', 'Potassium reduces blood pressure by promoting renal sodium excretion (natriuresis) and by direct vasodilatory effects on blood vessel walls. High potassium intake is consistently associated with lower blood pressure and reduced stroke risk in epidemiological studies, and is a key component of the DASH diet for hypertension management.', 'goal', '69d1c252-751c-49f5-8669-616f10db6658', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('potassium_r2_cardiovascular_health', 'Potassium reduces blood pressure by promoting renal sodium excretion (natriuresis) and by direct vasodilatory effects on blood vessel walls. High potassium intake is consistently associated with lower blood pressure and reduced stroke risk in epidemiological studies, and is a key component of the DASH diet for hypertension management.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r4_blood_pressure_support', 'Vitamin D receptors are expressed in cardiovascular tissue including cardiomyocytes and vascular smooth muscle. Vitamin D deficiency is associated with hypertension, arterial stiffness, and increased cardiovascular risk. While large RCT evidence for cardiovascular event reduction is mixed, ensuring adequate vitamin D status is mechanistically supported for vascular health.', 'goal', '69d1c252-751c-49f5-8669-616f10db6658', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r4_cardiovascular_health', 'Vitamin D receptors are expressed in cardiovascular tissue including cardiomyocytes and vascular smooth muscle. Vitamin D deficiency is associated with hypertension, arterial stiffness, and increased cardiovascular risk. While large RCT evidence for cardiovascular event reduction is mixed, ensuring adequate vitamin D status is mechanistically supported for vascular health.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r2_cardiovascular_health', 'Vitamin K activates matrix Gla protein (MGP), the most potent known inhibitor of vascular calcification. Undercarboxylated MGP accumulates in atherosclerotic plaques and calcified vessel walls when vitamin K is insufficient. Population studies show that higher menaquinone (K2) intake is inversely associated with cardiovascular mortality and arterial calcification.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r2_circulation_support', 'Vitamin K activates matrix Gla protein (MGP), the most potent known inhibitor of vascular calcification. Undercarboxylated MGP accumulates in atherosclerotic plaques and calcified vessel walls when vitamin K is insufficient. Population studies show that higher menaquinone (K2) intake is inversely associated with cardiovascular mortality and arterial calcification.', 'goal', '919247a7-6605-4a9c-9196-c1e20ea66f08', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r2_blood_pressure_support', 'Vitamin K activates matrix Gla protein (MGP), the most potent known inhibitor of vascular calcification. Undercarboxylated MGP accumulates in atherosclerotic plaques and calcified vessel walls when vitamin K is insufficient. Population studies show that higher menaquinone (K2) intake is inversely associated with cardiovascular mortality and arterial calcification.', 'goal', '69d1c252-751c-49f5-8669-616f10db6658', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r3_cardiovascular_health', 'Vitamin C supports cardiovascular health through multiple mechanisms: it is required for collagen synthesis in vessel walls, it regenerates oxidized vitamin E, it protects LDL from oxidation, and it promotes endothelial nitric oxide production leading to vasodilation. Higher vitamin C intake is associated with lower cardiovascular disease risk in prospective studies.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r3_circulation_support', 'Vitamin C supports cardiovascular health through multiple mechanisms: it is required for collagen synthesis in vessel walls, it regenerates oxidized vitamin E, it protects LDL from oxidation, and it promotes endothelial nitric oxide production leading to vasodilation. Higher vitamin C intake is associated with lower cardiovascular disease risk in prospective studies.', 'goal', '919247a7-6605-4a9c-9196-c1e20ea66f08', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r2_cardiovascular_health', 'Vitamin E is the primary lipid-soluble antioxidant in LDL particles, protecting them from oxidative modification. Oxidized LDL is a key initiating event in atherosclerotic plaque formation. While large RCTs have not shown consistent event reduction, observational studies and mechanistic evidence support the role of vitamin E in vascular protection.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r2_cholesterol_management', 'Vitamin E is the primary lipid-soluble antioxidant in LDL particles, protecting them from oxidative modification. Oxidized LDL is a key initiating event in atherosclerotic plaque formation. While large RCTs have not shown consistent event reduction, observational studies and mechanistic evidence support the role of vitamin E in vascular protection.', 'goal', '7e84e7b4-fa90-46bd-ac4c-216aac4b5c90', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('ubiquinol_r1_heart_rhythm_support', 'Coenzyme Q10 (ubiquinone) is essential for mitochondrial electron transport in cardiomyocytes, which have exceptionally high energy demands. CoQ10 levels are reduced in heart failure, cardiomyopathy, and with statin use. Supplementation has shown improvement in cardiac function and reduction in major cardiovascular events in some clinical trials. It is particularly relevant for individuals on statin therapy.', 'goal', '6dc227e1-ba1a-48e1-b009-c8aa69513a76', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('ubiquinol_r1_cardiovascular_health', 'Coenzyme Q10 (ubiquinone) is essential for mitochondrial electron transport in cardiomyocytes, which have exceptionally high energy demands. CoQ10 levels are reduced in heart failure, cardiomyopathy, and with statin use. Supplementation has shown improvement in cardiac function and reduction in major cardiovascular events in some clinical trials. It is particularly relevant for individuals on statin therapy.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('omega_3_r1_cholesterol_management', 'Omega-3 fatty acids (EPA and DHA) reduce triglyceride levels by 15–30% at doses of 2–4 g/day and have anti-inflammatory and anti-arrhythmic properties relevant to cardiovascular health. They are FDA-approved as prescription therapy for severe hypertriglyceridemia and are widely recommended in cardiovascular risk reduction guidelines.', 'goal', '7e84e7b4-fa90-46bd-ac4c-216aac4b5c90', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('omega_3_r1_cardiovascular_health', 'Omega-3 fatty acids (EPA and DHA) reduce triglyceride levels by 15–30% at doses of 2–4 g/day and have anti-inflammatory and anti-arrhythmic properties relevant to cardiovascular health. They are FDA-approved as prescription therapy for severe hypertriglyceridemia and are widely recommended in cardiovascular risk reduction guidelines.', 'goal', 'd4150c0d-79a4-4295-aedc-07bb12456691', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_k_r3_coagulation_support', 'Vitamin K is an essential cofactor for the gamma-carboxylation of coagulation factors II (prothrombin), VII, IX, and X, as well as anticoagulant proteins C, S, and Z. Without adequate vitamin K, these clotting factors are not properly activated and hemostasis is impaired. Vitamin K deficiency causes a clinically significant coagulopathy.', 'goal', 'd65c3114-f019-4a03-ac4a-1dddde10d096', 1, 'accumulate', true, '{"warning":"INDIVIDUALS ON WARFARIN OR OTHER VITAMIN K ANTAGONISTS MUST NOT CHANGE VITAMIN K INTAKE WITHOUT MEDICAL SUPERVISION — CHANGES WILL DIRECTLY AFFECT ANTICOAGULATION CONTROL."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r4_coagulation_support', 'Vitamin C is required for the synthesis and maintenance of collagen in vessel walls. Deficiency causes capillary fragility and abnormal bleeding (scurvy). Ensuring adequate vitamin C supports the structural integrity of blood vessels and contributes to normal hemostasis through the vascular component of coagulation.', 'goal', 'd65c3114-f019-4a03-ac4a-1dddde10d096', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b12_r2_cognitive_performance', 'Vitamin B12 is essential for myelin sheath synthesis and maintenance, neuronal DNA methylation, and the methionine cycle. Deficiency causes progressive neurological damage including cognitive impairment, memory loss, and dementia — effects that may be irreversible if untreated. Adequate B12 status is foundational for cognitive health across the lifespan.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b12_r2_neuroprotection', 'Vitamin B12 is essential for myelin sheath synthesis and maintenance, neuronal DNA methylation, and the methionine cycle. Deficiency causes progressive neurological damage including cognitive impairment, memory loss, and dementia — effects that may be irreversible if untreated. Adequate B12 status is foundational for cognitive health across the lifespan.', 'goal', '132a28dc-7ebb-45f3-b572-ebcd92d02200', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r2_cognitive_performance', 'Folate deficiency elevates homocysteine, which is neurotoxic at elevated levels and associated with brain atrophy, cognitive decline, and Alzheimer''s disease risk. Adequate folate supports one-carbon metabolism essential for neuronal DNA methylation and neurotransmitter synthesis. Randomized trials show that B9/B12/B6 combination slows brain atrophy in individuals with elevated homocysteine.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r2_neuroprotection', 'Folate deficiency elevates homocysteine, which is neurotoxic at elevated levels and associated with brain atrophy, cognitive decline, and Alzheimer''s disease risk. Adequate folate supports one-carbon metabolism essential for neuronal DNA methylation and neurotransmitter synthesis. Randomized trials show that B9/B12/B6 combination slows brain atrophy in individuals with elevated homocysteine.', 'goal', '132a28dc-7ebb-45f3-b572-ebcd92d02200', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b1_r1_cognitive_performance', 'Thiamin (vitamin B1) is an essential cofactor for pyruvate dehydrogenase and alpha-ketoglutarate dehydrogenase, enzymes central to glucose metabolism in the brain. The brain is uniquely dependent on glucose as a fuel source, and thiamin deficiency causes severe neurological dysfunction (Wernicke encephalopathy). Adequate thiamin is therefore critical for normal cognitive function and energy metabolism in neural tissue.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b1_r1_energy_and_vitality', 'Thiamin (vitamin B1) is an essential cofactor for pyruvate dehydrogenase and alpha-ketoglutarate dehydrogenase, enzymes central to glucose metabolism in the brain. The brain is uniquely dependent on glucose as a fuel source, and thiamin deficiency causes severe neurological dysfunction (Wernicke encephalopathy). Adequate thiamin is therefore critical for normal cognitive function and energy metabolism in neural tissue.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r2_cognitive_performance', 'Pyridoxal-5''-phosphate (the active form of vitamin B6) is required as a cofactor for the synthesis of serotonin (from tryptophan via aromatic amino acid decarboxylase), dopamine, GABA, and norepinephrine. These neurotransmitters are central to mood, cognition, and sleep regulation. B6 deficiency is associated with depression, confusion, and abnormal electroencephalographic activity.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r2_mood_support', 'Pyridoxal-5''-phosphate (the active form of vitamin B6) is required as a cofactor for the synthesis of serotonin (from tryptophan via aromatic amino acid decarboxylase), dopamine, GABA, and norepinephrine. These neurotransmitters are central to mood, cognition, and sleep regulation. B6 deficiency is associated with depression, confusion, and abnormal electroencephalographic activity.', 'goal', '80594958-c450-4dc2-9f53-7ed3347c03da', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b5_r1_cognitive_performance', 'Pantothenic acid (B5) is required for the synthesis of coenzyme A (CoA), which is essential for acetylcholine synthesis (via acetyl-CoA). Acetylcholine is the primary neurotransmitter of the cholinergic system, critical for memory and cognition. Cerebral B5 deficiency has been documented in Alzheimer''s disease brain tissue; adequate B5 may support cholinergic function and cognitive maintenance.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b5_r1_neuroprotection', 'Pantothenic acid (B5) is required for the synthesis of coenzyme A (CoA), which is essential for acetylcholine synthesis (via acetyl-CoA). Acetylcholine is the primary neurotransmitter of the cholinergic system, critical for memory and cognition. Cerebral B5 deficiency has been documented in Alzheimer''s disease brain tissue; adequate B5 may support cholinergic function and cognitive maintenance.', 'goal', '132a28dc-7ebb-45f3-b572-ebcd92d02200', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r5_neuroprotection', 'Vitamin D receptors are widely expressed throughout the brain. Vitamin D promotes neurotrophin production (including BDNF), reduces neuroinflammation, and is involved in amyloid clearance. Vitamin D deficiency is associated with cognitive decline, dementia risk, and higher Alzheimer''s disease incidence in prospective studies.', 'goal', '132a28dc-7ebb-45f3-b572-ebcd92d02200', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r5_cognitive_performance', 'Vitamin D receptors are widely expressed throughout the brain. Vitamin D promotes neurotrophin production (including BDNF), reduces neuroinflammation, and is involved in amyloid clearance. Vitamin D deficiency is associated with cognitive decline, dementia risk, and higher Alzheimer''s disease incidence in prospective studies.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r1_cognitive_performance', 'Iodine is required for thyroid hormone synthesis (T3 and T4). Thyroid hormones are essential for normal brain development in fetuses and infants, and for neurocognitive function in adults. Iodine deficiency is the world''s leading preventable cause of intellectual disability. Even mild deficiency in adults is associated with reduced cognitive performance.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r1_neuroprotection', 'Iodine is required for thyroid hormone synthesis (T3 and T4). Thyroid hormones are essential for normal brain development in fetuses and infants, and for neurocognitive function in adults. Iodine deficiency is the world''s leading preventable cause of intellectual disability. Even mild deficiency in adults is associated with reduced cognitive performance.', 'goal', '132a28dc-7ebb-45f3-b572-ebcd92d02200', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r1_thyroid_health', 'Iodine is required for thyroid hormone synthesis (T3 and T4). Thyroid hormones are essential for normal brain development in fetuses and infants, and for neurocognitive function in adults. Iodine deficiency is the world''s leading preventable cause of intellectual disability. Even mild deficiency in adults is associated with reduced cognitive performance.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r1_cognitive_performance', 'Iron is required for hemoglobin (oxygen delivery to the brain), myelin synthesis, and as a cofactor for tyrosine hydroxylase and tryptophan hydroxylase — the rate-limiting enzymes in dopamine and serotonin synthesis respectively. Iron deficiency anemia is associated with impaired attention, memory, and cognitive performance at any age. Correction improves cognitive outcomes in both children and adults.', 'goal', '35cdf35d-429f-44e2-94b4-bb7cea6a1e2e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r1_energy_and_vitality', 'Iron is required for hemoglobin (oxygen delivery to the brain), myelin synthesis, and as a cofactor for tyrosine hydroxylase and tryptophan hydroxylase — the rate-limiting enzymes in dopamine and serotonin synthesis respectively. Iron deficiency anemia is associated with impaired attention, memory, and cognitive performance at any age. Correction improves cognitive outcomes in both children and adults.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r6_mood_support', 'Vitamin D modulates serotonin synthesis and is involved in the regulation of dopamine neurocircuitry. Low vitamin D levels are consistently associated with higher rates of depression and seasonal affective disorder. Supplementation trials show modest improvement in depressive symptoms, particularly in individuals with vitamin D deficiency.', 'goal', '80594958-c450-4dc2-9f53-7ed3347c03da', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r6_stress_reduction', 'Vitamin D modulates serotonin synthesis and is involved in the regulation of dopamine neurocircuitry. Low vitamin D levels are consistently associated with higher rates of depression and seasonal affective disorder. Supplementation trials show modest improvement in depressive symptoms, particularly in individuals with vitamin D deficiency.', 'goal', '4ba0475a-69bd-4502-950d-9ddb4f620a4b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r4_mood_support', 'Magnesium modulates the NMDA glutamate receptor and the HPA (hypothalamic-pituitary-adrenal) stress axis. Low magnesium status is associated with increased anxiety, irritability, and depression. Magnesium depletion is exacerbated by chronic stress (urinary magnesium losses increase with cortisol elevation), creating a negative feedback cycle. Supplementation has shown benefit in reducing symptoms of depression and anxiety in several RCTs.', 'goal', '80594958-c450-4dc2-9f53-7ed3347c03da', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r4_stress_reduction', 'Magnesium modulates the NMDA glutamate receptor and the HPA (hypothalamic-pituitary-adrenal) stress axis. Low magnesium status is associated with increased anxiety, irritability, and depression. Magnesium depletion is exacerbated by chronic stress (urinary magnesium losses increase with cortisol elevation), creating a negative feedback cycle. Supplementation has shown benefit in reducing symptoms of depression and anxiety in several RCTs.', 'goal', '4ba0475a-69bd-4502-950d-9ddb4f620a4b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r3_mood_support', 'Folate is required for the synthesis of SAM (S-adenosylmethionine), the primary methyl donor used in monoamine neurotransmitter production. Folate deficiency is associated with lower SAM levels, impaired serotonin and dopamine synthesis, and depression. Low folate is found in a high proportion of depressed patients, and supplementation can augment antidepressant response.', 'goal', '80594958-c450-4dc2-9f53-7ed3347c03da', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r2_mood_support', 'Zinc is a modulator of NMDA and GABA receptors and is involved in regulation of serotonin reuptake. Zinc deficiency is associated with depression, anxiety, and impaired stress response. Low serum zinc is found in depressed patients, and zinc supplementation has shown benefit as an adjunct to antidepressant therapy in clinical trials.', 'goal', '80594958-c450-4dc2-9f53-7ed3347c03da', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r2_stress_reduction', 'Zinc is a modulator of NMDA and GABA receptors and is involved in regulation of serotonin reuptake. Zinc deficiency is associated with depression, anxiety, and impaired stress response. Low serum zinc is found in depressed patients, and zinc supplementation has shown benefit as an adjunct to antidepressant therapy in clinical trials.', 'goal', '4ba0475a-69bd-4502-950d-9ddb4f620a4b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r5_sleep_quality', 'Magnesium activates the parasympathetic nervous system and modulates GABA receptors, promoting relaxation and sleep onset. It also regulates circadian rhythm via melatonin precursor metabolism. Low magnesium is associated with insomnia and disturbed sleep. Clinical studies suggest supplementation improves subjective sleep quality, sleep efficiency, and early morning awakening, particularly in older adults.', 'goal', '5310d4a0-5241-4035-9098-2c3fe85a04eb', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r3_sleep_quality', 'Pyridoxal-5''-phosphate is required for the enzymatic conversion of 5-hydroxytryptophan to serotonin, and serotonin is the direct precursor to melatonin. B6 deficiency therefore impairs the serotonin→melatonin synthesis pathway, reducing melatonin availability for circadian regulation. Adequate B6 supports normal melatonin production and sleep-wake cycle regulation.', 'goal', '5310d4a0-5241-4035-9098-2c3fe85a04eb', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b1_r2_energy_and_vitality', 'Thiamin is an essential cofactor for pyruvate dehydrogenase and alpha-ketoglutarate dehydrogenase, both of which are rate-limiting steps in ATP production from carbohydrate metabolism. Deficiency causes fatigue, weakness, and peripheral neuropathy. Adequate thiamin is required for efficient cellular energy production.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b2_r1_energy_and_vitality', 'Riboflavin (vitamin B2) is the precursor to FMN and FAD, the two coenzymes essential for the electron transport chain (complexes I and II) and for fatty acid beta-oxidation. Riboflavin deficiency impairs mitochondrial energy production and is associated with fatigue and weakness. Adequate B2 is foundational for all energy-producing pathways.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b3_r3_energy_and_vitality', 'Niacin is the precursor for NAD+ and NADP+, which are central coenzymes in cellular respiration, glycolysis, the TCA cycle, and fatty acid oxidation. NAD+ is required for over 400 enzymatic reactions involved in energy metabolism. Depletion of NAD+ due to niacin insufficiency directly impairs energy production capacity.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b5_r2_energy_and_vitality', 'Pantothenic acid is required for the synthesis of coenzyme A (CoA), which is essential for the TCA cycle (as acetyl-CoA), fatty acid synthesis and oxidation, and the metabolism of carbohydrates, fats, and proteins. CoA is involved in more than 100 enzymatic reactions. Without adequate B5, energy metabolism at the cellular level is broadly impaired.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b7_r1_energy_and_vitality', 'Biotin is a cofactor for five carboxylase enzymes involved in gluconeogenesis (pyruvate carboxylase), fatty acid synthesis (acetyl-CoA carboxylase), and amino acid catabolism (propionyl-CoA carboxylase, 3-methylcrotonyl-CoA carboxylase, methylmalonyl-CoA mutase). These reactions span carbohydrate, fat, and protein metabolism; biotin deficiency therefore broadly impairs macronutrient-to-energy conversion.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r2_energy_and_vitality', 'Iron is the central component of hemoglobin and myoglobin, required for oxygen transport and delivery to tissues. It is also an essential component of mitochondrial cytochromes in the electron transport chain. Iron deficiency — even before frank anemia — causes fatigue, reduced physical endurance, and impaired work capacity. Correction of iron deficiency reliably improves energy and exercise tolerance.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r6_energy_and_vitality', 'ATP (adenosine triphosphate) is biologically active only when complexed with magnesium (as Mg-ATP). Magnesium is therefore a functional requirement for every ATP-dependent reaction in the body — including muscle contraction, protein synthesis, and all kinase-mediated reactions. Magnesium deficiency impairs energy availability at the cellular level even when ATP production is intact.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r5_energy_and_vitality', 'Vitamin C is required as a cofactor for two enzymes in carnitine biosynthesis (6-N-trimethyllysine dioxygenase and 4-N-trimethylaminobutyraldehyde dehydrogenase). Carnitine is essential for transporting long-chain fatty acids into mitochondria for beta-oxidation. Vitamin C deficiency impairs carnitine synthesis, reducing the capacity for fatty acid energy utilization and contributing to fatigue.', 'goal', '57edd86f-0710-456d-8765-6f16842b0c82', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r7_blood_sugar_regulation', 'Magnesium is a cofactor for tyrosine kinase activity of the insulin receptor. Low intracellular magnesium impairs insulin receptor signaling and glucose transporter (GLUT4) translocation, contributing to insulin resistance. Epidemiological studies consistently show inverse associations between magnesium intake and type 2 diabetes risk, and supplementation trials show improved insulin sensitivity in hypomagnesemic subjects.', 'goal', '1965e819-1720-486e-8b2d-b11d55e3032b', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('chromium_r1_blood_sugar_regulation', 'Chromium potentiates insulin receptor signaling, possibly through its role as part of oligopeptide chromodulin (LMWCr). Controlled studies have shown that chromium supplementation improves glycemic control and insulin sensitivity in individuals with impaired glucose tolerance and type 2 diabetes, though evidence quality varies. Adequate chromium status supports normal glucose metabolism.', 'goal', '1965e819-1720-486e-8b2d-b11d55e3032b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b7_r2_blood_sugar_regulation', 'Biotin activates pyruvate carboxylase, the enzyme that initiates gluconeogenesis (glucose production from non-carbohydrate precursors). Biotin also modulates gene expression of glucokinase, which regulates glucose sensing in pancreatic beta cells. Pharmacological biotin doses have been shown to lower fasting glucose in some diabetic subjects, though evidence is preliminary.', 'goal', '1965e819-1720-486e-8b2d-b11d55e3032b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r3_blood_sugar_regulation', 'Zinc is structurally required for the crystallization and storage of insulin in pancreatic beta cell granules, and plays a role in insulin secretion. Zinc also contributes to antioxidant defense in beta cells. Low zinc status is associated with increased diabetes risk and impaired glycemic control. Supplementation has shown modest improvements in glycated hemoglobin in some trials.', 'goal', '1965e819-1720-486e-8b2d-b11d55e3032b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r7_blood_sugar_regulation', 'Vitamin D receptors are expressed in pancreatic beta cells, and vitamin D promotes insulin secretion. Vitamin D deficiency is associated with insulin resistance and increased risk of type 2 diabetes. Some intervention studies show that adequate vitamin D improves beta cell function and insulin sensitivity, though results are not fully consistent.', 'goal', '1965e819-1720-486e-8b2d-b11d55e3032b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r8_weight_management', 'Vitamin D deficiency is common in obesity (adipose tissue sequesters vitamin D) and is associated with impaired leptin signaling, insulin resistance, and higher adiposity. Correcting vitamin D deficiency may support metabolic improvements during weight loss, though direct evidence for weight loss from vitamin D supplementation alone is limited.', 'goal', 'f0d6c0ee-e401-4e17-9b14-f06bb302639b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r2_weight_management', 'Epidemiological and intervention data suggest that adequate calcium intake, particularly from dairy sources, is associated with reduced body fat accumulation. Proposed mechanisms include: suppression of calcitriol (which promotes lipogenesis), increased fecal fat excretion by forming insoluble calcium-fatty acid complexes, and suppression of parathyroid hormone. Effects are modest and diet-context dependent.', 'goal', 'f0d6c0ee-e401-4e17-9b14-f06bb302639b', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r2_thyroid_health', 'Iodine is the essential structural component of both T3 (triiodothyronine) and T4 (thyroxine), the two thyroid hormones. Without adequate iodine, the thyroid gland cannot produce these hormones, leading to hypothyroidism, goiter, and — in pregnancy — irreversible cognitive impairment in the developing fetus. Iodine adequacy is a non-negotiable requirement for thyroid function.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 1, 'accumulate', true, '{"warning":"EXCESS IODINE (>1100 MCG/DAY IN ADULTS) CAN TRIGGER OR WORSEN AUTOIMMUNE THYROID DISEASE (HASHIMOTO''S OR GRAVES'') AND SHOULD NOT BE EXCEEDED."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r2_thyroid_health', 'Selenium is an essential component of iodothyronine deiodinases, the enzymes that convert inactive T4 to active T3 in peripheral tissues. It is also a component of glutathione peroxidase, which protects thyroid follicular cells from H2O2 generated during thyroid hormone synthesis. Selenium deficiency impairs both hormone activation and thyroid cell integrity. Supplementation has shown benefit in reducing anti-thyroid antibodies in autoimmune thyroiditis.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r3_thyroid_health', 'Thyroid peroxidase (TPO) is a heme-containing enzyme that requires iron for catalytic activity. Iron deficiency impairs TPO function and reduces thyroid hormone synthesis efficiency. Iron deficiency anemia has been associated with impaired thyroid function and reduced responsiveness to iodine supplementation in deficient populations.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r4_thyroid_health', 'Zinc is required for the zinc finger domain structure of nuclear thyroid hormone receptors (TR-alpha and TR-beta). Without adequate zinc, these receptors cannot bind T3 and activate gene transcription. Low zinc status is associated with lower T3 and T4 levels in population studies, and zinc supplementation has shown modest benefit in thyroid function markers.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r6_immune_support', 'Vitamin C has multiple well-characterized immune functions: it accumulates in phagocytic cells to support oxidative burst against pathogens, it stimulates neutrophil migration and function, promotes T-lymphocyte proliferation, and supports epithelial barrier integrity. Clinical trials show that vitamin C reduces the duration and severity of respiratory infections and may reduce incidence in individuals under high physical stress.', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r6_anti_inflammatory_support', 'Vitamin C has multiple well-characterized immune functions: it accumulates in phagocytic cells to support oxidative burst against pathogens, it stimulates neutrophil migration and function, promotes T-lymphocyte proliferation, and supports epithelial barrier integrity. Clinical trials show that vitamin C reduces the duration and severity of respiratory infections and may reduce incidence in individuals under high physical stress.', 'goal', '4faf3fe8-57c4-47fc-8853-2f40e9bb66df', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r9_immune_support', 'Vitamin D is a potent immunomodulator. It induces antimicrobial peptide synthesis (cathelicidin) in innate immune cells, promotes regulatory T cells (Tregs) to dampen autoimmune and inflammatory responses, and modulates the TH1/TH2 balance. Vitamin D deficiency is associated with increased susceptibility to respiratory infections, autoimmune disease, and impaired vaccination response.', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r9_anti_inflammatory_support', 'Vitamin D is a potent immunomodulator. It induces antimicrobial peptide synthesis (cathelicidin) in innate immune cells, promotes regulatory T cells (Tregs) to dampen autoimmune and inflammatory responses, and modulates the TH1/TH2 balance. Vitamin D deficiency is associated with increased susceptibility to respiratory infections, autoimmune disease, and impaired vaccination response.', 'goal', '4faf3fe8-57c4-47fc-8853-2f40e9bb66df', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r1_immune_support', 'Vitamin A is required for the differentiation of T and B lymphocytes, natural killer cells, and dendritic cells. Retinoic acid (the active form) promotes production of IgA antibodies at mucosal surfaces, which are the first line of defense against pathogens. Vitamin A deficiency substantially increases susceptibility to infection, especially respiratory and gastrointestinal infections.', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r5_immune_support', 'Zinc is essential for thymic development and T lymphocyte maturation. It supports the activity of over 300 metalloenzymes involved in immune cell proliferation. Zinc deficiency causes thymic atrophy, lymphopenia, and impaired cytokine production. Zinc supplementation reduces susceptibility to pneumonia, diarrhea, and malaria in deficient populations and reduces duration of the common cold.', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r3_immune_support', 'Selenium, as a component of thioredoxin reductase and glutathione peroxidase, is required for antioxidant defense in immune cells. It supports T cell proliferation, natural killer cell activity, and antibody production. Selenium deficiency impairs immune responses and has been associated with increased viral mutation rates (enhanced pathogen virulence).', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r3_anti_inflammatory_support', 'Selenium, as a component of thioredoxin reductase and glutathione peroxidase, is required for antioxidant defense in immune cells. It supports T cell proliferation, natural killer cell activity, and antibody production. Selenium deficiency impairs immune responses and has been associated with increased viral mutation rates (enhanced pathogen virulence).', 'goal', '4faf3fe8-57c4-47fc-8853-2f40e9bb66df', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r3_immune_support', 'Vitamin E supplementation has demonstrated enhancement of immune responses in older adults — a population with a physiological age-related decline in immune function (immunosenescence). RCTs show increased T cell proliferation, improved antibody responses to vaccination, and reduced respiratory infection incidence with vitamin E supplementation in older individuals.', 'goal', '2311cc52-d1d6-4844-9d17-34c705a4bb88', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r10_anti_inflammatory_support', 'Vitamin D suppresses the production of pro-inflammatory cytokines (TNF-alpha, IL-6, IL-1beta) and promotes anti-inflammatory cytokines (IL-10). Low vitamin D status is associated with elevated inflammatory markers (CRP, IL-6) across multiple chronic diseases. Supplementation has shown reductions in CRP and other inflammatory biomarkers in several RCTs, particularly in deficient individuals.', 'goal', '4faf3fe8-57c4-47fc-8853-2f40e9bb66df', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r8_anti_inflammatory_support', 'Magnesium inhibits NF-kB activation, a master regulator of inflammatory gene expression. Low magnesium status is associated with elevated CRP, IL-6, and TNF-alpha in population studies. Magnesium deficiency activates the NLRP3 inflammasome. Supplementation reduces inflammatory markers in hypomagnesemic individuals.', 'goal', '4faf3fe8-57c4-47fc-8853-2f40e9bb66df', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r11_gut_microbiome_support', 'Vitamin D regulates intestinal epithelial tight junctions and promotes production of antimicrobial peptides (defensins) in gut epithelial cells. Low vitamin D is associated with increased intestinal permeability ("leaky gut"), dysbiosis, and inflammatory bowel disease activity. Adequate vitamin D status supports gut barrier integrity and a balanced gut immune response.', 'goal', '2a7087e7-67a9-4458-9baa-54c5eb3e6606', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r11_digestive_comfort', 'Vitamin D regulates intestinal epithelial tight junctions and promotes production of antimicrobial peptides (defensins) in gut epithelial cells. Low vitamin D is associated with increased intestinal permeability ("leaky gut"), dysbiosis, and inflammatory bowel disease activity. Adequate vitamin D status supports gut barrier integrity and a balanced gut immune response.', 'goal', '180a1457-78dd-4964-9f1a-9e9e1cede5a6', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r2_gut_microbiome_support', 'Vitamin A and retinoic acid are essential for the differentiation of gut-associated lymphoid tissue (GALT), production of IgA at mucosal surfaces, and maintenance of intestinal epithelial integrity. Deficiency disrupts gut mucosal immunity, increases susceptibility to enteric infections, and impairs intestinal barrier function.', 'goal', '2a7087e7-67a9-4458-9baa-54c5eb3e6606', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r2_digestive_comfort', 'Vitamin A and retinoic acid are essential for the differentiation of gut-associated lymphoid tissue (GALT), production of IgA at mucosal surfaces, and maintenance of intestinal epithelial integrity. Deficiency disrupts gut mucosal immunity, increases susceptibility to enteric infections, and impairs intestinal barrier function.', 'goal', '180a1457-78dd-4964-9f1a-9e9e1cede5a6', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r6_gut_microbiome_support', 'Zinc is required for the maintenance of tight junction proteins (occludin, claudin) in intestinal epithelial cells. Zinc deficiency increases intestinal permeability and is associated with diarrhea and enteric infection susceptibility. Supplementation reduces diarrhea duration and severity, particularly in malnourished populations, and supports gut barrier repair.', 'goal', '2a7087e7-67a9-4458-9baa-54c5eb3e6606', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r6_digestive_comfort', 'Zinc is required for the maintenance of tight junction proteins (occludin, claudin) in intestinal epithelial cells. Zinc deficiency increases intestinal permeability and is associated with diarrhea and enteric infection susceptibility. Supplementation reduces diarrhea duration and severity, particularly in malnourished populations, and supports gut barrier repair.', 'goal', '180a1457-78dd-4964-9f1a-9e9e1cede5a6', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r4_liver_health', 'Vitamin E (800 IU/day of alpha-tocopherol) is recommended by the American Association for the Study of Liver Diseases (AASLD) as a first-line pharmacological treatment for non-alcoholic steatohepatitis (NASH) in non-diabetic adults. The PIVENS trial demonstrated significant histological improvement in liver inflammation and fibrosis with vitamin E supplementation. Oxidative stress is a central mechanism in NASH pathogenesis.', 'goal', 'c5d0c396-ddc3-4c8f-9512-11b1b30efb47', 10, 'accumulate', true, '{"warning":"LONG-TERM HIGH-DOSE VITAMIN E (>400 IU/DAY) HAS BEEN ASSOCIATED WITH INCREASED ALL-CAUSE MORTALITY AND INCREASED HEMORRHAGIC STROKE RISK IN SOME META-ANALYSES. USE AT THIS DOSE LEVEL REQUIRES MEDICAL SUPERVISION."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b12_r3_liver_health', 'The liver is the primary site of the methionine cycle, in which B12 and folate are required to regenerate SAM (S-adenosylmethionine), the universal methyl donor. SAM depletion impairs hepatic phosphatidylcholine synthesis and the export of VLDL, contributing to hepatic fat accumulation. Adequate B12 supports hepatic methylation and lipid export.', 'goal', 'c5d0c396-ddc3-4c8f-9512-11b1b30efb47', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r7_skin_health', 'Vitamin C is required as a cofactor for prolyl and lysyl hydroxylases that stabilize the triple helix of collagen, the primary structural protein of the skin''s dermis. It also promotes collagen gene expression and is a key antioxidant in the skin against UV-induced oxidative damage. Adequate vitamin C intake is associated with better skin appearance, less wrinkling, and improved wound healing.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r3_skin_health', 'Retinoic acid (vitamin A''s active metabolite) regulates keratinocyte differentiation and proliferation, maintaining normal skin architecture. Vitamin A deficiency causes hyperkeratosis and follicular plugging. Topical retinoids are established anti-aging and anti-acne therapies. Systemic vitamin A adequacy supports skin barrier integrity and sebaceous gland regulation.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r12_skin_health', 'Keratinocytes express vitamin D receptors and the enzyme CYP27B1 for local activation of vitamin D. Vitamin D regulates keratinocyte proliferation, promotes skin barrier lipid synthesis, and has anti-inflammatory effects relevant to atopic dermatitis and psoriasis. Low vitamin D is associated with worse outcomes in inflammatory skin conditions.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r7_skin_health', 'Zinc is essential for wound healing: it supports keratinocyte migration and proliferation, promotes collagen synthesis by fibroblasts, and has antimicrobial properties in wound beds. Zinc deficiency causes dermatitis, acrodermatitis enteropathica, and impaired wound healing. Oral zinc supplementation reduces healing time in zinc-deficient individuals.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r5_skin_health', 'Vitamin E is the primary lipid-soluble antioxidant in skin cell membranes and sebum. It is concentrated in the stratum corneum, where it protects against UV-induced lipid peroxidation and oxidative damage. Dietary vitamin E and topical application both contribute to skin photoprotection. Vitamin E and C act synergistically in skin antioxidant defense.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r4_skin_health', 'Selenium is incorporated into glutathione peroxidase and thioredoxin reductase in skin cells, providing protection against oxidative stress from UV exposure and environmental pollutants. Low selenium status has been associated with increased risk of skin cancer and inflammatory skin conditions in some studies.', 'goal', '5fa81151-2285-4bcb-914d-e2aec70c2471', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b7_r3_hair_health', 'Biotin deficiency causes hair thinning and alopecia. Biotin is a cofactor for carboxylases required in fatty acid synthesis and keratin protein metabolism, both relevant to hair follicle proliferation. While there is no strong evidence for high-dose biotin benefit in non-deficient individuals, adequate biotin is required for normal hair growth and is commonly supplemented for hair health.', 'goal', '4a6a0381-cc32-462b-9659-fb5591c864f1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r4_hair_health', 'Iron deficiency is among the most common nutritional causes of diffuse hair loss (telogen effluvium) in women. Hair follicle matrix cells are highly mitotically active and have high iron requirements. Low serum ferritin correlates with increased hair shedding and thinning, and iron repletion restores normal hair cycle in deficient individuals.', 'goal', '4a6a0381-cc32-462b-9659-fb5591c864f1', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r8_hair_health', 'Zinc is required for hair follicle matrix cell proliferation and for the activity of 5-alpha reductase (androgen metabolism in the follicle). Zinc deficiency causes hair loss (including alopecia areata in severe cases). Adequate zinc supports normal hair follicle cycling and structural protein synthesis.', 'goal', '4a6a0381-cc32-462b-9659-fb5591c864f1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r13_hair_health', 'Vitamin D receptors are expressed in hair follicle keratinocytes and are required for normal hair follicle cycling. Vitamin D receptor knockout mice develop alopecia. Low vitamin D levels have been associated with alopecia areata and diffuse hair thinning in observational studies. Supplementation has shown benefit in some alopecia areata trials.', 'goal', '4a6a0381-cc32-462b-9659-fb5591c864f1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b5_r3_hair_health', 'Pantothenic acid is required for CoA synthesis. CoA is involved in the lipid and acetylation reactions required for melanin production in hair follicle melanocytes. Animal models show that B5 deficiency causes premature hair graying, reversed by B5 administration — a specific nutrient-reversal cycle supporting extend_conclusion for premature graying in humans.', 'goal', '4a6a0381-cc32-462b-9659-fb5591c864f1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b7_r4_nail_health', 'Biotin deficiency is associated with brittle, thin, and splitting nails (onychorrhexis). Biotin is required for keratin production, the structural protein of nails. Several case series and small trials suggest that biotin supplementation (2.5 mg/day) increases nail plate thickness and reduces brittleness, though large RCTs are lacking.', 'goal', '8e9089a5-5760-48fe-ab66-5ffd0accb664', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r9_nail_health', 'Zinc deficiency causes beau''s lines, leukonychia (white spots), and nail fragility. Zinc is required for keratinocyte proliferation in the nail matrix and for normal keratinization. Adequate zinc supports normal nail structure, growth rate, and resistance to fracture.', 'goal', '8e9089a5-5760-48fe-ab66-5ffd0accb664', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r5_nail_health', 'Koilonychia (spoon-shaped nails), nail brittleness, and ridging are recognized signs of iron deficiency. Iron is required for the high-turnover keratinocyte proliferation of nail matrix cells. Correction of iron deficiency resolves iron-related nail abnormalities.', 'goal', '8e9089a5-5760-48fe-ab66-5ffd0accb664', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r4_vision_support', 'Vitamin A (as 11-cis-retinal) is the chromophore component of rhodopsin and cone photopsins — the photoreceptor pigments in rods and cones. Without adequate vitamin A, rhodopsin cannot regenerate after light exposure, causing night blindness and, in severe deficiency, irreversible xerophthalmia and corneal blindness. Vitamin A supplementation is the primary treatment for deficiency-related eye disease.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 1, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r4_eye_health', 'Vitamin A (as 11-cis-retinal) is the chromophore component of rhodopsin and cone photopsins — the photoreceptor pigments in rods and cones. Without adequate vitamin A, rhodopsin cannot regenerate after light exposure, causing night blindness and, in severe deficiency, irreversible xerophthalmia and corneal blindness. Vitamin A supplementation is the primary treatment for deficiency-related eye disease.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 1, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r8_vision_support', 'The aqueous humor of the eye contains exceptionally high concentrations of vitamin C (20–60x plasma levels), where it protects the lens from UV-induced oxidative damage that drives cataract formation. Prospective cohort studies consistently show that higher vitamin C intake and higher lens vitamin C concentration are associated with lower risk of age-related cataract.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r8_eye_health', 'The aqueous humor of the eye contains exceptionally high concentrations of vitamin C (20–60x plasma levels), where it protects the lens from UV-induced oxidative damage that drives cataract formation. Prospective cohort studies consistently show that higher vitamin C intake and higher lens vitamin C concentration are associated with lower risk of age-related cataract.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r6_vision_support', 'Vitamin E protects photoreceptor outer segment membranes — which are unusually rich in polyunsaturated fatty acids — from lipid peroxidation caused by light-induced oxidative stress. The AREDS (Age-Related Eye Disease Study) demonstrated that a combination including vitamin E significantly reduced progression from intermediate to advanced AMD. It is part of the standard AREDS2 formula for AMD management.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r6_eye_health', 'Vitamin E protects photoreceptor outer segment membranes — which are unusually rich in polyunsaturated fatty acids — from lipid peroxidation caused by light-induced oxidative stress. The AREDS (Age-Related Eye Disease Study) demonstrated that a combination including vitamin E significantly reduced progression from intermediate to advanced AMD. It is part of the standard AREDS2 formula for AMD management.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r10_vision_support', 'Zinc is found in high concentrations in the retinal pigment epithelium (RPE) of the macula. It is required for the activity of several retinal enzymes and for the transport of vitamin A from liver to the retina. The AREDS trial showed that high-dose zinc (80 mg/day) combined with antioxidants significantly reduced progression to advanced AMD. Zinc is a core component of AREDS2.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 10, 'accumulate', true, '{"warning":"HIGH-DOSE ZINC (80 MG/DAY AS IN AREDS) REQUIRES CO-SUPPLEMENTATION WITH COPPER (2 MG/DAY) TO PREVENT ZINC-INDUCED COPPER DEFICIENCY ANEMIA."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r10_eye_health', 'Zinc is found in high concentrations in the retinal pigment epithelium (RPE) of the macula. It is required for the activity of several retinal enzymes and for the transport of vitamin A from liver to the retina. The AREDS trial showed that high-dose zinc (80 mg/day) combined with antioxidants significantly reduced progression to advanced AMD. Zinc is a core component of AREDS2.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 10, 'accumulate', true, '{"warning":"HIGH-DOSE ZINC (80 MG/DAY AS IN AREDS) REQUIRES CO-SUPPLEMENTATION WITH COPPER (2 MG/DAY) TO PREVENT ZINC-INDUCED COPPER DEFICIENCY ANEMIA."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('copper_r1_vision_support', 'High-dose zinc supplementation (as used in AREDS2 for AMD prevention) inhibits intestinal copper absorption by inducing metallothionein, which sequesters copper in enterocytes. This can cause copper deficiency anemia. The AREDS protocol specifies 2 mg/day of copper (as cupric oxide) to offset this effect. Copper must be co-supplemented whenever zinc doses exceed 40 mg/day.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 1, 'accumulate', true, '{"warning":"FAILURE TO CO-SUPPLEMENT COPPER WITH HIGH-DOSE ZINC CAN CAUSE COPPER DEFICIENCY ANEMIA AND NEUROLOGICAL DAMAGE."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('copper_r1_eye_health', 'High-dose zinc supplementation (as used in AREDS2 for AMD prevention) inhibits intestinal copper absorption by inducing metallothionein, which sequesters copper in enterocytes. This can cause copper deficiency anemia. The AREDS protocol specifies 2 mg/day of copper (as cupric oxide) to offset this effect. Copper must be co-supplemented whenever zinc doses exceed 40 mg/day.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 1, 'accumulate', true, '{"warning":"FAILURE TO CO-SUPPLEMENT COPPER WITH HIGH-DOSE ZINC CAN CAUSE COPPER DEFICIENCY ANEMIA AND NEUROLOGICAL DAMAGE."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r5_vision_support', 'Selenium-dependent glutathione peroxidase is expressed in the retinal pigment epithelium, where it neutralizes lipid peroxides generated by photo-oxidative stress. Inadequate selenium may compromise this defense mechanism, increasing susceptibility to AMD and retinal degeneration. Lower selenium levels have been observed in AMD patients compared to controls in some studies.', 'goal', '7767e70c-95b3-409e-abd8-bab7dae1afb9', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r5_eye_health', 'Selenium-dependent glutathione peroxidase is expressed in the retinal pigment epithelium, where it neutralizes lipid peroxides generated by photo-oxidative stress. Inadequate selenium may compromise this defense mechanism, increasing susceptibility to AMD and retinal degeneration. Lower selenium levels have been observed in AMD patients compared to controls in some studies.', 'goal', '1e7c3838-a0bd-49d5-b12a-59fc42a0e8a9', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r4_prenatal_health', 'Folic acid (400–800 mcg/day before conception and through the first trimester) is required for neural tube closure, which occurs at days 21–28 of gestation. Periconceptional folic acid supplementation reduces neural tube defect risk by approximately 70%. This is one of the most evidence-supported nutritional interventions in obstetrics and is mandated in many public health guidelines globally.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 1, 'accumulate', true, '{"additional_conditions":["(pregnancy:true) OR (prenatal:true)|apply_level=require|action=PROVIDE|ingredient=VITAMIN_B9|amount=(gt:400)|unit=mcg|subtype=folic_acid"],"remark":"Women with a previous NTD-affected pregnancy require 4,000 mcg/day (prescription dose); this standard rule covers the general population."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r4_fertility_support', 'Folic acid (400–800 mcg/day before conception and through the first trimester) is required for neural tube closure, which occurs at days 21–28 of gestation. Periconceptional folic acid supplementation reduces neural tube defect risk by approximately 70%. This is one of the most evidence-supported nutritional interventions in obstetrics and is mandated in many public health guidelines globally.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 1, 'accumulate', true, '{"additional_conditions":["(pregnancy:true) OR (prenatal:true)|apply_level=require|action=PROVIDE|ingredient=VITAMIN_B9|amount=(gt:400)|unit=mcg|subtype=folic_acid"],"remark":"Women with a previous NTD-affected pregnancy require 4,000 mcg/day (prescription dose); this standard rule covers the general population."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_a_r5_prenatal_health', 'High-dose preformed vitamin A (retinol) is teratogenic. Doses above 3,000 mcg RAE/day during pregnancy are associated with craniofacial, cardiac, and central nervous system birth defects. The tolerable upper intake level for pregnancy is 3,000 mcg RAE/day. Beta-carotene does not carry this risk.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 1, 'accumulate', true, '{"additional_conditions":["(pregnancy:true)|apply_level=require|action=AVOID|ingredient=VITAMIN_A|amount=(gt:3)|unit=mg RAE|subtype=RETINOLS"],"warning":"HIGH-DOSE PREFORMED VITAMIN A (RETINOL) IS TERATOGENIC. DO NOT EXCEED 3,000 MCG RAE/DAY DURING PREGNANCY. CONSULT A HEALTHCARE PROVIDER BEFORE SUPPLEMENTING WITH VITAMIN A IN PREGNANCY."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r6_prenatal_health', 'Iron requirements increase substantially during pregnancy (from 18 mg/day to 27 mg/day RDA) due to expanded maternal blood volume, placental transfer to the fetus, and preparation for blood loss at delivery. Iron deficiency anemia in pregnancy is associated with preterm birth, low birth weight, and impaired neonatal neurodevelopment. Universal iron supplementation in pregnancy is recommended by WHO.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 1, 'accumulate', true, '{"additional_conditions":["(pregnancy:true)|apply_level=require|action=PROVIDE|ingredient=IRON|amount=(gt:27)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r14_prenatal_health', 'Vitamin D is required for fetal calcium homeostasis and skeletal mineralization, and adequate maternal vitamin D is associated with improved neonatal bone density, reduced preeclampsia risk, and better immune programming of the newborn. The WHO and national health bodies recommend vitamin D supplementation throughout pregnancy.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 10, 'accumulate', true, '{"additional_conditions":["(pregnancy:true)|apply_level=recommend|action=PROVIDE|ingredient=VITAMIN_D|amount=(gt:600)|unit=IU|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r3_prenatal_health', 'Iodine requirements increase by approximately 50% during pregnancy (RDA: 220 mcg vs. 150 mcg non-pregnant). The fetus is entirely dependent on maternal iodine for thyroid hormone synthesis in the first trimester, when fetal brain development is most sensitive to thyroid hormone. Even mild iodine deficiency in pregnancy causes measurable cognitive deficits in offspring.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 1, 'accumulate', true, '{"additional_conditions":["(pregnancy:true)|apply_level=require|action=PROVIDE|ingredient=IODINE|amount=(gt:220)|unit=mcg|subtype=ANY"],"warning":"IODINE EXCESS DURING PREGNANCY CAN ALSO CAUSE FETAL HYPOTHYROIDISM. DO NOT EXCEED THE TOLERABLE UPPER LIMIT OF 1100 MCG/DAY."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r3_prenatal_health', 'The fetal skeleton accumulates approximately 30 g of calcium during pregnancy, primarily in the third trimester. If maternal dietary calcium is inadequate, the fetus draws calcium from maternal bone, potentially reducing maternal BMD. Adequate calcium intake during pregnancy protects maternal skeletal reserves and supports fetal bone mineralization. High-dose calcium (1.5–2 g/day) also reduces preeclampsia risk in calcium-deficient populations.', 'goal', 'b1f21e0f-1c29-4ff7-b2b8-c3cdd750dc9b', 10, 'accumulate', true, '{"additional_conditions":["(pregnancy:true)|apply_level=recommend|action=PROVIDE|ingredient=CALCIUM|amount=(gt:1000)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b9_r5_fertility_support', 'Adequate folate status is required before conception for DNA synthesis and cell division during early embryonic development. Folate is required from the moment of fertilization; since neural tube closure occurs before most women know they are pregnant, supplementation must begin preconceptionally. Folate also supports male fertility by maintaining sperm DNA integrity.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r11_fertility_support', 'Zinc is highly concentrated in the prostate and spermatozoa. It is required for testosterone synthesis, sperm motility, and protection of sperm DNA from oxidative damage. Zinc deficiency causes hypogonadism and reduced sperm count. Zinc supplementation has been shown to improve sperm parameters in subfertile men.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 10, 'accumulate', true, '{"additional_conditions":["(gender:male)|apply_level=recommend|action=PROVIDE|ingredient=ZINC|amount=(gt:RDA)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r6_fertility_support', 'Selenium is a component of phospholipid hydroperoxide glutathione peroxidase (GPx4), which is specifically expressed in spermatocytes and is required for sperm motility and structural integrity of the sperm midpiece. Selenium deficiency is associated with impaired sperm motility and male subfertility.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 50, 'accumulate', true, '{"additional_conditions":["(gender:male)|apply_level=extend_conclusion|action=PROVIDE|ingredient=SELENIUM|amount=(gt:RDA)|unit=mcg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r15_fertility_support', 'Vitamin D receptors are expressed in ovaries, testes, and the pituitary. Vitamin D is involved in AMH (anti-Müllerian hormone) production, folliculogenesis in women, and testosterone synthesis in men. Low vitamin D is associated with reduced fertility outcomes, poorer IVF success rates, and lower sperm quality.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r7_fertility_support', 'Iron deficiency has been associated with ovulatory infertility in prospective studies (Nurses'' Health Study). The Heme iron suppressor of ovulation is a proposed mechanism. Ensuring adequate iron stores before conception supports normal ovulatory cycling and reduces risk of ovulatory infertility.', 'goal', 'bc8239ce-27d2-452a-a394-ddf9fa3524d4', 50, 'accumulate', true, '{"additional_conditions":["(gender:female)|apply_level=extend_conclusion|action=PROVIDE|ingredient=IRON|amount=(gt:RDA)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r4_menopause_support', 'Estrogen decline at menopause accelerates osteoclast activity and bone resorption, substantially increasing fracture risk. Calcium (1,200 mg/day) combined with vitamin D is the standard of care for post-menopausal bone preservation. Adequate calcium intake delays osteoporotic fracture onset and is essential baseline therapy in menopause-related bone loss.', 'goal', '33fe5ca8-7147-43fc-a21d-825d7dd86bad', 10, 'accumulate', true, '{"additional_conditions":["(condition:postmenopausal)|apply_level=recommend|action=PROVIDE|ingredient=CALCIUM|amount=(gt:1200)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('calcium_r4_osteoporosis_prevention', 'Estrogen decline at menopause accelerates osteoclast activity and bone resorption, substantially increasing fracture risk. Calcium (1,200 mg/day) combined with vitamin D is the standard of care for post-menopausal bone preservation. Adequate calcium intake delays osteoporotic fracture onset and is essential baseline therapy in menopause-related bone loss.', 'goal', 'be897c89-36e2-41df-8d41-f81be787e6ab', 10, 'accumulate', true, '{"additional_conditions":["(condition:postmenopausal)|apply_level=recommend|action=PROVIDE|ingredient=CALCIUM|amount=(gt:1200)|unit=mg|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r16_menopause_support', 'Post-menopausal women have reduced skin synthesis of vitamin D and often have inadequate dietary intake, making supplementation important for maintaining calcium absorption and bone mineral density. Vitamin D also supports immune function and mood, both of which are relevant in the menopause transition.', 'goal', '33fe5ca8-7147-43fc-a21d-825d7dd86bad', 10, 'accumulate', true, '{"additional_conditions":["(condition:postmenopausal)|apply_level=recommend|action=PROVIDE|ingredient=VITAMIN_D|amount=(gt:800)|unit=IU|subtype=ANY"]}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r9_menopause_support', 'Magnesium may help alleviate menopause-related symptoms including insomnia, mood disturbances, and palpitations. Estrogen decline reduces magnesium absorption and cellular magnesium levels. Additionally, magnesium deficiency exacerbates HPA axis dysregulation, which contributes to hot flashes. Supplementation may reduce symptom burden through nervous system and vascular effects.', 'goal', '33fe5ca8-7147-43fc-a21d-825d7dd86bad', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r12_mens_health', 'Zinc is required for the synthesis of testosterone in Leydig cells (as a cofactor for the enzyme chain converting cholesterol to testosterone). It is also the most concentrated mineral in the prostate gland, where it inhibits 5-alpha reductase and has antiproliferative effects. Zinc deficiency causes hypogonadism and low testosterone; supplementation restores testosterone in deficient men.', 'goal', '65cd60cd-0c98-4309-a64d-8aaed1246c7e', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('selenium_r7_mens_health', 'Selenium has demonstrated antiproliferative effects in prostate tissue, primarily through induction of apoptosis and antioxidant protection of prostate DNA. Observational studies suggested an inverse association between selenium status and prostate cancer risk, though large RCT evidence (SELECT trial) was not supportive at pharmacological doses. Nutritional adequacy (not pharmacological supplementation) remains defensible for prostate protection.', 'goal', '65cd60cd-0c98-4309-a64d-8aaed1246c7e', 50, 'accumulate', true, '{"warning":"HIGH-DOSE SELENIUM SUPPLEMENTATION (>400 MCG/DAY) IS ASSOCIATED WITH INCREASED PROSTATE CANCER RISK IN MEN WITH ALREADY-ADEQUATE SELENIUM STATUS (SELECT TRIAL). DO NOT EXCEED THE UL OF 400 MCG/DAY.","remark":"The SELECT trial (selenium 200 mcg/day) did not reduce prostate cancer risk and showed a non-significant trend toward increased risk in men with high baseline selenium. This rule is for nutritional adequacy, not pharmacological supplementation."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r17_mens_health', 'Vitamin D receptors are expressed in Sertoli and Leydig cells of the testis. Vitamin D is involved in testosterone synthesis and sperm function. Low vitamin D is associated with lower testosterone levels in men, and some intervention trials have shown modest testosterone increases with supplementation in deficient men.', 'goal', '65cd60cd-0c98-4309-a64d-8aaed1246c7e', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iron_r8_exercise_performance', 'Iron is the rate-limiting nutrient for aerobic exercise performance. It is required for hemoglobin (O2 delivery), myoglobin (O2 storage in muscle), and mitochondrial cytochromes (oxidative phosphorylation). Even pre-anemic iron depletion (low ferritin without anemia) significantly impairs VO2max and endurance performance. Female athletes and endurance athletes are at particularly high risk of iron deficiency.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r10_exercise_performance', 'Magnesium requirements increase with physical activity due to losses in sweat and urine and increased metabolic demand. Magnesium is required for ATP synthesis, glucose utilization, and lactate clearance during exercise. Magnesium depletion reduces exercise performance, increases oxygen cost of exercise, and promotes muscle cramping. Supplementation improves exercise performance in deficient athletes.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r18_exercise_performance', 'Vitamin D supports muscle strength, power output, and reaction time through nuclear VDR-mediated gene expression in muscle cells. Vitamin D deficiency is associated with reduced muscle mass, impaired fast-twitch muscle fiber function, and increased injury risk in athletes. Athletes who train indoors or live at high latitudes are at particular risk of deficiency.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b1_r3_exercise_performance', 'Thiamin requirements increase proportionally with carbohydrate intake and energy expenditure. Athletes consuming high-carbohydrate diets for performance have increased thiamin needs, as pyruvate dehydrogenase (thiamin-dependent) is the rate-limiting step in glucose entry into the TCA cycle. Marginal thiamin deficiency can impair high-intensity carbohydrate-fueled exercise capacity.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r9_exercise_performance', 'Intense endurance exercise temporarily suppresses immune function ("open window" of increased infection susceptibility). Vitamin C supplementation in athletes has been shown in meta-analyses to reduce incidence of upper respiratory infections following high physical stress. It also reduces cortisol response to exercise stress and attenuates muscle damage markers, supporting recovery.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r9_recovery_support', 'Intense endurance exercise temporarily suppresses immune function ("open window" of increased infection susceptibility). Vitamin C supplementation in athletes has been shown in meta-analyses to reduce incidence of upper respiratory infections following high physical stress. It also reduces cortisol response to exercise stress and attenuates muscle damage markers, supporting recovery.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r19_recovery_support', 'Vitamin D has anti-inflammatory properties that are relevant to post-exercise recovery. It reduces pro-inflammatory cytokine production (IL-6, TNF-alpha) that contributes to delayed onset muscle soreness (DOMS). Adequate vitamin D is also associated with faster return to play after musculoskeletal injury in athlete populations.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r11_recovery_support', 'Magnesium is required for muscle relaxation (antagonizing calcium-driven contraction), ATP-mediated cellular repair, and protein synthesis. Post-exercise magnesium losses in sweat can be substantial. Supplementation reduces muscle soreness scores and DOMS in some trials, and supports the anabolic recovery phase by enabling protein synthesis.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 10, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_c_r10_recovery_support', 'Post-exercise collagen synthesis in tendons, ligaments, and bones requires vitamin C as a hydroxylase cofactor. A recent RCT demonstrated that consuming 48 mg of vitamin C prior to a bout of exercise significantly increased circulating collagen precursors, supporting connective tissue repair. Vitamin C is therefore clinically relevant for both muscle and connective tissue recovery after exercise.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r13_recovery_support', 'Zinc is required for the activity of over 300 enzymes involved in protein synthesis and repair, including RNA polymerases and ribosomal proteins. Zinc is lost in sweat during intense exercise. Deficiency impairs muscle protein synthesis and anabolic hormone responsiveness (including IGF-1 and testosterone signaling), slowing recovery from training.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r7_recovery_support', 'Intense exercise generates substantial reactive oxygen species (ROS) through increased mitochondrial flux. Vitamin E as a membrane antioxidant protects muscle cell membranes from lipid peroxidation during and after strenuous activity. Deficiency exacerbates exercise-induced muscle membrane damage; however, excessive antioxidant supplementation may blunt beneficial training adaptations. Nutritional adequacy rather than pharmacological dosing is the appropriate target.', 'goal', 'da217b2d-a755-4280-826f-8aa603239530', 50, 'accumulate', true, '{"warning":"VERY HIGH DOSES OF ANTIOXIDANT SUPPLEMENTS (INCLUDING VITAMIN E >400 IU/DAY) DURING TRAINING MAY BLUNT EXERCISE-INDUCED ADAPTATIONS INCLUDING INSULIN SENSITIVITY IMPROVEMENTS. PRIORITIZE DIETARY ADEQUACY OVER SUPPLEMENTATION FOR ACTIVE INDIVIDUALS."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_e_r7_exercise_performance', 'Intense exercise generates substantial reactive oxygen species (ROS) through increased mitochondrial flux. Vitamin E as a membrane antioxidant protects muscle cell membranes from lipid peroxidation during and after strenuous activity. Deficiency exacerbates exercise-induced muscle membrane damage; however, excessive antioxidant supplementation may blunt beneficial training adaptations. Nutritional adequacy rather than pharmacological dosing is the appropriate target.', 'goal', '8a7b1be3-486a-45e1-9e4c-3786ea3695c1', 50, 'accumulate', true, '{"warning":"VERY HIGH DOSES OF ANTIOXIDANT SUPPLEMENTS (INCLUDING VITAMIN E >400 IU/DAY) DURING TRAINING MAY BLUNT EXERCISE-INDUCED ADAPTATIONS INCLUDING INSULIN SENSITIVITY IMPROVEMENTS. PRIORITIZE DIETARY ADEQUACY OVER SUPPLEMENTATION FOR ACTIVE INDIVIDUALS."}') ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_d_r20_hormonal_balance', 'Vitamin D is structurally a secosteroid and shares biosynthetic machinery with steroid hormones. Vitamin D receptors are expressed in ovaries, testes, adrenal glands, and pituitary — all key endocrine organs. Vitamin D is involved in modulating estrogen, testosterone, and adrenal steroid synthesis. Low vitamin D is associated with hormonal dysregulation including PCOS, low testosterone, and adrenal insufficiency patterns.', 'goal', '40435a74-c3e4-4f0e-a0a1-5df980c35d25', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('magnesium_r12_hormonal_balance', 'Magnesium is required for the activity of steroidogenic enzymes in the adrenal and gonadal pathways. It modulates the HPA (hypothalamic-pituitary-adrenal) axis, reducing excessive cortisol responses. Magnesium deficiency amplifies cortisol secretion, contributing to hormonal imbalance. It also supports aromatase activity balance, relevant to estrogen-testosterone ratios in both sexes.', 'goal', '40435a74-c3e4-4f0e-a0a1-5df980c35d25', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('vitamin_b6_r4_hormonal_balance', 'Pyridoxal-5''-phosphate (active B6) is required for hepatic metabolism and clearance of steroid hormones including estrogen. B6 deficiency is associated with elevated estrogen levels. Additionally, B6 supports progesterone receptor sensitivity and is clinically used in PMS/PMDD management where hormonal dysregulation drives mood and somatic symptoms.', 'goal', '40435a74-c3e4-4f0e-a0a1-5df980c35d25', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('zinc_r14_hormonal_balance', 'Zinc inhibits aromatase (the enzyme that converts testosterone to estrogen), helping maintain testosterone-estrogen ratios in both men and women. In women, zinc supports progesterone synthesis and folliculogenesis. In men, zinc is required for testosterone synthesis and inhibits excess estrogen conversion. Zinc deficiency causes hormonal dysregulation across multiple axes.', 'goal', '40435a74-c3e4-4f0e-a0a1-5df980c35d25', 50, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r4_hormonal_balance', 'Thyroid hormones (T3 and T4) are master regulators of metabolic rate, fertility hormones, and the sensitivity of other endocrine receptors. Iodine deficiency disrupts the entire hormonal network: it raises TSH, reduces T3/T4, impairs estrogen clearance, and reduces ovarian sensitivity to FSH and LH. Adequate iodine is foundational for overall hormonal balance.', 'goal', '40435a74-c3e4-4f0e-a0a1-5df980c35d25', 1, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
INSERT INTO public.rules (rule_name, description, trigger_type, trigger_node_id, priority, conflict_strategy, is_active, metadata) VALUES ('iodine_r4_thyroid_health', 'Thyroid hormones (T3 and T4) are master regulators of metabolic rate, fertility hormones, and the sensitivity of other endocrine receptors. Iodine deficiency disrupts the entire hormonal network: it raises TSH, reduces T3/T4, impairs estrogen clearance, and reduces ovarian sensitivity to FSH and LH. Adequate iodine is foundational for overall hormonal balance.', 'goal', '33787a38-6c97-4674-ad6c-481f43ab9de0', 1, 'accumulate', true, NULL) ON CONFLICT (rule_name) DO NOTHING;
